#!/bin/sh
###############################################################################
# Kibana Data Views + Dashboard Auto-Init
#
# Creates data views and two logging dashboards (Prod + Dev) via Kibana API.
# Idempotent — ignores already-existing objects.
# Runs as one-shot container after Kibana is healthy.
###############################################################################
set -e

KIBANA_URL="http://kibana:5601"

create_data_view() {
  id="$1"
  name="$2"
  pattern="$3"

  echo "Creating data view: $name ($pattern) ..."
  status=$(curl -s -o /dev/null -w "%{http_code}" \
    -X POST "$KIBANA_URL/api/data_views/data_view" \
    -H "kbn-xsrf: true" \
    -H "Content-Type: application/json" \
    -d "{\"data_view\":{\"id\":\"$id\",\"title\":\"$pattern\",\"name\":\"$name\",\"timeFieldName\":\"@timestamp\",\"allowNoIndex\":true}}")

  if [ "$status" = "200" ]; then
    echo "  -> Created."
  elif [ "$status" = "409" ]; then
    echo "  -> Already exists, skipping."
  else
    echo "  -> Unexpected status $status (continuing anyway)."
  fi
}

set_default_data_view() {
  id="$1"
  echo "Setting default data view: $id ..."
  curl -s -o /dev/null \
    -X POST "$KIBANA_URL/api/data_views/default" \
    -H "kbn-xsrf: true" \
    -H "Content-Type: application/json" \
    -d "{\"data_view_id\":\"$id\",\"force\":true}"
  echo "  -> Done."
}

create_runtime_field() {
  id="$1"
  name="$2"
  echo "Creating runtime field '$name' on data view $id ..."
  status=$(curl -s -o /dev/null -w "%{http_code}" \
    -X PUT "$KIBANA_URL/api/data_views/data_view/$id/runtime_field" \
    -H "kbn-xsrf: true" \
    -H "Content-Type: application/json" \
    -d "{\"name\":\"$name\",\"runtimeField\":{\"type\":\"long\",\"script\":{\"source\":\"emit(doc['@timestamp'].value.toInstant().toEpochMilli() / 86400000L)\"}}}")
  if [ "$status" = "200" ]; then
    echo "  -> Created/updated."
  else
    echo "  -> Status $status (continuing anyway)."
  fi
}

delete_saved_object() {
  type="$1"
  id="$2"
  echo "Deleting saved object $type/$id ..."
  curl -s -o /dev/null \
    -X DELETE "$KIBANA_URL/api/saved_objects/$type/$id" \
    -H "kbn-xsrf: true"
  echo "  -> Done."
}

create_lens_viz() {
  id="$1"
  echo "Creating Lens visualization: $id ..."
  status=$(curl -s -o /tmp/lens-result.txt -w "%{http_code}" \
    -X POST "$KIBANA_URL/api/saved_objects/lens/$id?overwrite=true" \
    -H "kbn-xsrf: true" \
    -H "Content-Type: application/json" \
    -d '{
      "attributes": {
        "title": "User-Aktivitaet (letzte 7 Tage)",
        "description": "",
        "visualizationType": "lnsDatatable",
        "state": {
          "datasourceStates": {
            "formBased": {
              "currentIndexPatternId": "all-logs",
              "layers": {
                "layer1": {
                  "columnOrder": ["col-visitor","col-puzzle","col-endless","col-daily","col-kurs","col-weekly","col-days"],
                  "columns": {
                    "col-visitor": {"label":"Visitor / User","customLabel":true,"dataType":"string","operationType":"terms","scale":"ordinal","sourceField":"fields.VisitorId.keyword","isBucketed":true,"params":{"size":50,"orderBy":{"type":"column","columnId":"col-days"},"orderDirection":"desc","otherBucket":false,"missingBucket":false}},
                    "col-puzzle":  {"label":"#puzzle","customLabel":true,"dataType":"number","operationType":"count","scale":"ratio","isBucketed":false,"sourceField":"___records___","filter":{"query":"messageTemplate.keyword: PuzzleAttempt*","language":"kuery"}},
                    "col-endless": {"label":"#endless","customLabel":true,"dataType":"number","operationType":"count","scale":"ratio","isBucketed":false,"sourceField":"___records___","filter":{"query":"messageTemplate.keyword: EndlessSessionCompleted*","language":"kuery"}},
                    "col-daily":   {"label":"#daily","customLabel":true,"dataType":"number","operationType":"count","scale":"ratio","isBucketed":false,"sourceField":"___records___","filter":{"query":"messageTemplate.keyword: BookPuzzleAttempt*","language":"kuery"}},
                    "col-kurs":    {"label":"#kurs","customLabel":true,"dataType":"number","operationType":"count","scale":"ratio","isBucketed":false,"sourceField":"___records___","filter":{"query":"messageTemplate.keyword: CoursePuzzleAttempt*","language":"kuery"}},
                    "col-weekly":  {"label":"#weekly","customLabel":true,"dataType":"number","operationType":"count","scale":"ratio","isBucketed":false,"sourceField":"___records___","filter":{"query":"messageTemplate.keyword: WeeklyPostAttempt*","language":"kuery"}},
                    "col-days":    {"label":"#tageaktiv","customLabel":true,"dataType":"number","operationType":"unique_count","scale":"ratio","sourceField":"day_bucket","isBucketed":false,"params":{"emptyAsNull":true}}
                  },
                  "incompleteColumns": {}
                }
              }
            }
          },
          "visualization": {
            "layerId": "layer1",
            "layerType": "data",
            "columns": [
              {"columnId":"col-visitor","isTransposed":false,"width":200},
              {"columnId":"col-puzzle","isTransposed":false},
              {"columnId":"col-endless","isTransposed":false},
              {"columnId":"col-daily","isTransposed":false},
              {"columnId":"col-kurs","isTransposed":false},
              {"columnId":"col-weekly","isTransposed":false},
              {"columnId":"col-days","isTransposed":false}
            ],
            "paging": {"size": 50, "enabled": true},
            "sorting": {"columnId": "col-days", "direction": "desc"}
          },
          "query": {"query": "messageTemplate.keyword: PuzzleAttempt* OR messageTemplate.keyword: EndlessSessionCompleted* OR messageTemplate.keyword: BookPuzzleAttempt* OR messageTemplate.keyword: CoursePuzzleAttempt* OR messageTemplate.keyword: WeeklyPostAttempt*", "language": "kuery"},
          "filters": []
        }
      },
      "references": [{"type": "index-pattern", "id": "all-logs", "name": "indexpattern-datasource-layer-layer1"}]
    }')
  if [ "$status" = "200" ]; then
    echo "  -> Created/updated."
  else
    echo "  -> Status $status."
    cat /tmp/lens-result.txt 2>/dev/null || true
    echo ""
  fi
}

