# 1) Data Views
create_data_view "rookhub-logs" "RookHub Logs" "rookhub-logs-*"
create_data_view "rookhub-dev-logs" "RookHub Dev Logs" "rookhub-dev-logs-*"
create_data_view "crawler-logs" "Crawler Logs" "crawler-logs-*"
create_data_view "all-logs" "Alle Logs" "*-logs-*"

# 2) Set default
set_default_data_view "all-logs"

# 2b) Runtime fields
create_runtime_field "all-logs" "day_bucket"

# 3) Remove old combined dashboard if it exists
delete_saved_object "dashboard" "rookhub-logging-dashboard"

# 4) Import viz objects + prod + dev dashboards
import_dashboard

# 5) Lens-Visualisierungen (direkt via Saved Objects API, nicht per Import)
create_lens_viz "user-activity-table"

echo "Kibana init complete."
